+/// Result of setting up a single worker.
+#[derive(Debug, Clone, Serialize)]
+struct SetupResult {
+    worker_id: String,
+    success: bool,
+    binary_deployed: bool,
+    toolchain_synced: bool,
+    errors: Vec<String>,
+}
